import React from "react"
import moment from "moment";
import { properties } from '../../properties/properties.js'
var xlsx = require("xlsx");


class Scheduler extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, selectedFile: null, amionData: [], rotationName: []
        };
    }

    handleselectedFile = event => {
        //console.log(event.target.files[0])
        this.setState({
          selectedFile: event.target.files[0]
        })
      }


    handleUpload = (e) => {

        this.setState({screen: 1})

        e.preventDefault();
        var results = []
        var forAmionStartDate = ""
        var forAmionEndDate = ""
        var yearInfo = []
        var rotationArr = []

        /*
        var startDate = ""
        var endDate = ""
*/
/*
        var wb = xlsx.readFile(this.state.selectedFile);


        var wsR1 = wb.Sheets[wb.SheetNames[0]];
        var wsR2 = wb.Sheets[wb.SheetNames[1]];
        var wsR3 = wb.Sheets[wb.SheetNames[2]];


        this.findRotation("UC Card", wsR1)
        */
        var reader = new FileReader();
        const scope = this;
        reader.onload = function (e) {

            function findRotation(forWhichRotation, ws, sheetName) {

                var range = xlsx.utils.decode_range(ws['!ref']);

                var yearInfoString = []

                for (let colNum = 0; colNum <= range.e.c; colNum++) {
                    var yearRow = findV(ws[xlsx.utils.encode_cell({r: 0, c: colNum})])
                    if (yearRow.length > 0 && isNaN(yearRow.substring(0,1))) {
                        yearInfoString = yearRow.split(",")
                    }
                }


                yearInfo = yearInfoString[1].trim().split("-").map(item=>item.trim())
                //console.log(yearInfo)

                var lastDate = ""



                for (let colNum = 0; colNum <= range.e.c; colNum++) {

                    var rotationRow = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum})])


                    if (rotationRow.length > 0 && !isNaN(rotationRow.substring(0,1))) {

                        var splitDate = rotationRow.split(" ")

                        var yearString = yearInfo[0]

                        var startDate = moment(splitDate[1] + "/" + yearString, "M/D/YYYY").format("YYYY-MM-DD")
                        var endDate = moment(splitDate[3] + "/" + yearString, "M/D/YYYY").format("YYYY-MM-DD")

                        if (lastDate.length > 0 && startDate < lastDate) {
                            startDate = moment(splitDate[1] + "/" + yearInfo[1], "M/D/YYYY").format("YYYY-MM-DD")
                        }
                        if (lastDate.length > 0 && endDate < lastDate) {
                            endDate = moment(splitDate[3] + "/" + yearInfo[1], "M/D/YYYY").format("YYYY-MM-DD")
                        }

                        if (forAmionStartDate === "" || startDate < forAmionStartDate) {
                            forAmionStartDate = startDate
                        }

                        if (forAmionEndDate === "" || endDate > forAmionEndDate) {
                            forAmionEndDate = endDate
                        }


                        lastDate = endDate

                       //console.log("*******************************************************************")
                       //console.log(rotationRow)
                       for (let rowNum = 3; rowNum <= range.e.r; rowNum++) {
                           /*
                            var splitDate = rotationRow.split(" ")
                           if (startDate == "") {
                               startDate = splitDate[1] + "/" + moment().format("YYYY")
                               console.log(startDate)
                           }
                           endDate = splitDate[3] + "/" + moment().format("YYYY")
                           console.log(endDate)
                           */

                           var isRotation = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum})])
